        if name == "calendar.upcoming":
            return {"events": [{"title": f"E{i}",
                                   "due_date": "2099-01-01"}
                                   for i in range(20)]}
        if name == "contracts.list":
            return {"count": 0, "total_monthly_cost": 0.0}
        return {}
    out = dashboard_summary(many_dispatch)
